"use client"

import * as React from "react"
import { IconAlertTriangle, IconCircleCheck, IconClockExclamation } from "@tabler/icons-react"

import { Badge } from "@gunjo/ui"

import { currencyState, daysUntil, type CurrencyState } from "./data"

// ──────────────────────────────────────────────────────────────────────────
// 期限カレンシー表示（自前実装）
//
// @gunjo/ui には「基準日 vs 有効期限 → 有効/期限間近/失効」を判定する専用部品が
// 無い（docs/by-use-case でも "期限カレンシーの専用部品は未提供" と明記）。
// 数値レンジ判定の ReferenceValue は日付を扱えないため、状態判定は data.ts の
// currencyState() で行い、表示は @gunjo/ui の Badge（色＋アイコンで色のみに依存
// しない）に寄せて自前合成している。
// ──────────────────────────────────────────────────────────────────────────

const CONFIG: Record<
  CurrencyState,
  { variant: "success" | "warning" | "destructive"; icon: React.ReactNode; srLabel: string }
> = {
  有効: { variant: "success", icon: <IconCircleCheck />, srLabel: "有効" },
  期限間近: { variant: "warning", icon: <IconClockExclamation />, srLabel: "期限間近" },
  失効: { variant: "destructive", icon: <IconAlertTriangle />, srLabel: "失効" },
}

function formatJaDate(iso: string): string {
  const [y, m, d] = iso.split("-")
  return `${y}/${m}/${d}`
}

/** 残日数を人間可読に（失効は「○日超過」） */
export function remainingLabel(expiry: string): string {
  const d = daysUntil(expiry)
  if (d < 0) return `${Math.abs(d)}日超過`
  if (d === 0) return "本日まで"
  return `残${d}日`
}

/** 期限だけを状態色で見せる小型ピル（表セル用） */
export function CurrencyPill({
  expiry,
  showDate = true,
}: {
  expiry: string
  showDate?: boolean
}) {
  const state = currencyState(expiry)
  const cfg = CONFIG[state]
  return (
    <Badge variant={cfg.variant} icon={cfg.icon}>
      <span className="sr-only">{cfg.srLabel}：</span>
      {showDate ? formatJaDate(expiry) : state}
      <span className="ml-1 font-normal opacity-80">（{remainingLabel(expiry)}）</span>
    </Badge>
  )
}

/** 資格名 + 期限ピル の行（詳細パネル用） */
export function CurrencyRow({
  kind,
  expiry,
  note,
}: {
  kind: string
  expiry: string
  note?: string
}) {
  return (
    <div className="flex items-center justify-between gap-3 py-1.5">
      <div className="min-w-0">
        <div className="text-sm font-medium text-foreground">{kind}</div>
        {note ? <div className="text-xs text-muted-foreground">{note}</div> : null}
      </div>
      <CurrencyPill expiry={expiry} />
    </div>
  )
}

