// ── 期限の状態判定（純関数・SSOTの代替）─────────────────────────────────
// 基準日からの残日数で 有効/期限間近/失効 を導出。@gunjo/ui に期限カレンシー
// 専用部品が無いため、ここで自前判定する（後述レポート参照）。
export const TODAY = "2026-06-28"

export function daysUntil(expiry: string, from: string = TODAY): number {
  const a = new Date(expiry + "T00:00:00")
  const b = new Date(from + "T00:00:00")
  return Math.round((a.getTime() - b.getTime()) / 86_400_000)
}

/** 失効: 期限切れ / 期限間近: 60日以内 / 有効: それ以外 */
export function currencyState(expiry: string, from: string = TODAY): CurrencyState {
  const d = daysUntil(expiry, from)
  if (d < 0) return "失効"
  if (d <= 60) return "期限間近"
  return "有効"
}

/** ドライバーの最悪の資格状態（失効 > 期限間近 > 有効） */
export function worstCurrency(d: Driver): CurrencyState {
  const states = d.currencies.map((c) => currencyState(c.expiry))
  if (states.includes("失効")) return "失効"
  if (states.includes("期限間近")) return "期限間近"
  return "有効"
}

export function suiage(r: DailyReport): number {
  // 水揚＝運賃＋迎車料＋割増（高速立替は乗客からの預り金で売上に含めない運用）
  return r.fare + r.pickup + r.premium
}

export function jissyaRate(r: DailyReport): number {
  return Math.round((r.loadedKm / r.totalKm) * 1000) / 10
}

