"use client"

import * as React from "react"
import {
  IconAlertTriangle,
  IconTestPipe,
  IconCalendarStats,
  IconClipboardCheck,
  IconClock,
  IconGauge,
  IconLock,
  IconReceiptYen,
  IconStethoscope,
  IconUserCheck,
} from "@tabler/icons-react"

import {
  ActionQueue,
  Alert,
  AlertDescription,
  AlertTitle,
  AmountBreakdown,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CheckList,
  CoSign,
  type CoSignValue,
  DataTable,
  Meter,
  MetadataList,
  PersonCell,
  ReferenceValue,
