} from "./data"
import { CurrencyPill, CurrencyRow, remainingLabel } from "./CurrencyPill"

// ── アルコール検知値の判定（0.00 が合格、>0 は no-go）──────────────────────
// 数値 vs しきい値の ReferenceValue を流用：criticalHigh=0.01 で 0.00 超を異常に。
function AlcoholReading({ value }: { value: number | null }) {
  if (value == null) {
    return <span className="text-sm text-muted-foreground">—</span>
  }
  return (
    <ReferenceValue
      value={value}
      range={{ criticalHigh: 0.01 }} // 0.01mg/L 以上で異常（=検知）
      unit="mg/L"
      format={(v) => v.toFixed(2)}
      labels={{ normal: "規定値内", "critical-high": "検知（出庫不可）" }}
      showLabel
    />
  )
}

// 点呼状態のピル
function CallStatePill({ driver }: { driver: Driver }) {
  const dep = driver.rollCall.departure
  if (dep.state === "対象外") {
    return <Badge variant="secondary">対象外</Badge>
  }
  // 出庫アルコール検知は最優先で no-go
  if (dep.alcohol != null && dep.alcohol > 0) {
    return (
      <Badge variant="destructive" icon={<IconTestPipe />}>
        出庫不可
      </Badge>
    )
  }
  if (dep.state === "完了") {
    return (
      <Badge variant="success" icon={<IconUserCheck />}>
        出庫点呼済
      </Badge>
    )
  }
  return (
    <Badge variant="warning" icon={<IconAlertTriangle />}>
      未了
    </Badge>
  )
}

export function TaxiCrewConsole() {
  const [selectedId, setSelectedId] = React.useState<string>(ON_DUTY[0]?.id ?? DRIVERS[0].id)
  const selected = DRIVERS.find((d) => d.id === selectedId) ?? DRIVERS[0]

  // 点呼記録の確認（署名でロック）状態
  const [signoff, setSignoff] = React.useState<Record<string, CoSignValue | undefined>>({})

  // ── 要対応キュー（点呼未了・資格失効/間近・拘束/連続超過・健康異常・アルコール検知）──
  const actionItems = React.useMemo(() => {
    const items: React.ComponentProps<typeof ActionQueue>["items"] = []
    for (const d of DRIVERS) {
      const dep = d.rollCall.departure
      // アルコール検知（最優先）
      if (dep.alcohol != null && dep.alcohol > 0) {
        items.push({
          id: `${d.id}-alc`,
          severity: "critical",
          kind: "アルコール検知",
          title: `${d.name}：出庫点呼で ${dep.alcohol.toFixed(2)}mg/L 検知`,
          detail: "出庫不可。再測定・原因聴取・乗務差し替えを実施。",
          meta: dep.at,
          actions: (
            <Button size="xs" variant="destructive" onClick={() => setSelectedId(d.id)}>
              対応
            </Button>
          ),
        })
      }
      // 資格失効・間近
      for (const c of d.currencies) {
        const st = currencyState(c.expiry)
        if (st === "失効") {
          items.push({
            id: `${d.id}-${c.kind}-exp`,
            severity: "critical",
            kind: "資格失効",
            title: `${d.name}：${c.kind} が失効`,
            detail: `有効期限 ${c.expiry}（${remainingLabel(c.expiry)}）。即時乗務停止。`,
            meta: remainingLabel(c.expiry),
            actions: (
              <Button size="xs" variant="outline" onClick={() => setSelectedId(d.id)}>
                確認
              </Button>
            ),
          })
        } else if (st === "期限間近") {
          items.push({
            id: `${d.id}-${c.kind}-soon`,
            severity: "warning",
            kind: "更新期限",
            title: `${d.name}：${c.kind} 期限間近`,
            detail: `有効期限 ${c.expiry}。更新手続きを案内。`,
            meta: remainingLabel(c.expiry),
          })
        }
      }
      // 点呼未了（出番なのに出庫点呼が未了）
      if (d.shift === "出番" && dep.state === "未了") {
        items.push({
          id: `${d.id}-call`,
          severity: "warning",
          kind: "点呼未了",
          title: `${d.name}：出庫点呼が未了`,
          detail: "出庫前に対面/IT点呼・アルコールチェックを実施。",
        })
      }
      // 連続乗務 超過接近
      if (d.renzokuMin >= KAIZEN.renzokuLimitMin - 10 && d.renzokuMin > 0) {
        items.push({
          id: `${d.id}-renzoku`,
          severity: "warning",
          kind: "連続乗務",
          title: `${d.name}：連続乗務が上限に接近`,
          detail: `${Math.floor(d.renzokuMin / 60)}時間${d.renzokuMin % 60}分／上限 ${
            KAIZEN.renzokuLimitMin / 60
          }時間。休憩指示。`,
          meta: "要休憩",
        })
      }
      // 健康確認 異常
      if (dep.health === "要観察" || dep.health === "不良") {
        items.push({
          id: `${d.id}-health`,
          severity: dep.health === "不良" ? "critical" : "info",
          kind: "健康確認",
          title: `${d.name}：健康確認「${dep.health}」`,
          detail: dep.instruction ?? "体調変化に注意・必要に応じ乗務見合わせ。",
        })
      }
    }
    return items
  }, [])

  // ── KPI ──
  const onDutyCount = ON_DUTY.length
  const callDoneCount = ON_DUTY.filter(
    (d) => d.rollCall.departure.state === "完了" && !(d.rollCall.departure.alcohol! > 0)
  ).length
  const expiringCount = DRIVERS.filter((d) => worstCurrency(d) !== "有効").length
  const actionCount = actionItems.length

  return (
    <div className="space-y-6">
      {/* ── KPI ストリップ（RSC-safe な形だが、selectedId 連動のためクライアント側）── */}
      <StatGroup
        cols={{ base: 2, md: 4 }}
        items={[
          { label: "本日の出番", value: `${onDutyCount}名`, hint: `全乗務員 ${DRIVERS.length}名` },
          {
            label: "出庫点呼済",
            value: `${callDoneCount}/${onDutyCount}`,
            trend: callDoneCount < onDutyCount ? "down" : "flat",
            tone: callDoneCount < onDutyCount ? "negative" : "positive",
            hint: "アルコール検知者を除く",
          },
          {
            label: "資格 失効・間近",
            value: `${expiringCount}名`,
            trend: expiringCount > 0 ? "down" : "flat",
            tone: expiringCount > 0 ? "negative" : "neutral",
            hint: "二種免許 / 適性 / 健診",
          },
          {
            label: "要対応",
            value: `${actionCount}件`,
            trend: actionCount > 0 ? "down" : "flat",
            tone: actionCount > 0 ? "negative" : "neutral",
          },
        ]}
      />

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1fr)_380px]">
        {/* ── 左：乗務員名簿（点呼・資格・拘束）── */}
        <div className="min-w-0 space-y-6">
          <RosterTable
            drivers={DRIVERS}
            selectedId={selectedId}
            onSelect={setSelectedId}
          />

          {/* 選択した乗務員の詳細 */}
          <DriverDetail
            driver={selected}
            signoff={signoff[selected.id]}
            onSign={(v) => setSignoff((s) => ({ ...s, [selected.id]: v }))}
          />
        </div>

        {/* ── 右：要対応キュー ── */}
        <aside className="min-w-0 space-y-4">
          <Card>
            <CardHeader className="flex-row items-center justify-between gap-2 space-y-0">
              <CardTitle className="flex items-center gap-2 text-base">
                <IconAlertTriangle className="size-5 text-warning" aria-hidden />
                要対応
              </CardTitle>
              <Badge variant={actionCount > 0 ? "warning" : "secondary"}>{actionCount}件</Badge>
            </CardHeader>
            <CardContent>
              <ActionQueue items={actionItems} emptyLabel="対応が必要な項目はありません" />
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="space-y-0 pb-2">
              <CardTitle className="text-sm text-muted-foreground">点呼執行体制</CardTitle>
            </CardHeader>
            <CardContent className="space-y-1 text-sm">
              <p className="font-medium text-foreground">{CENTER.callExecutor}</p>
              <p className="text-xs text-muted-foreground">{CENTER.operator}</p>
              <Separator className="my-2" />
              <p className="text-xs text-muted-foreground">
                {CENTER.weather}
              </p>
            </CardContent>
          </Card>
        </aside>
      </div>
    </div>
  )
}

// ── 名簿テーブル ───────────────────────────────────────────────────────────
function RosterTable({
  drivers,
  selectedId,
  onSelect,
}: {
  drivers: Driver[]
  selectedId: string
  onSelect: (id: string) => void
}) {
  const columns = React.useMemo<ColumnDef<Driver>[]>(
    () => [
      {
        id: "driver",
        header: "乗務員",
        accessorFn: (d) => d.name,
        cell: ({ row }) => {
          const d = row.original
          return (
            <PersonCell
              name={d.name}
              secondary={`${d.kana}・社員№${d.empNo}`}
              tertiary={`${d.team}／${d.employment}${d.vehicle ? `／${d.vehicle}` : ""}`}
              avatarClassName="bg-primary/15 text-foreground"
            />
          )
        },
      },
      {
        id: "shift",
        header: "勤務",
        accessorFn: (d) => d.shift,
        cell: ({ row }) => {
          const s = row.original.shift
          return (
            <Badge variant={s === "出番" ? "info" : s === "明番" ? "secondary" : "outline"}>
              {s}
            </Badge>
          )
        },
      },
      {
        id: "call",
        header: "出庫点呼",
        accessorFn: (d) => d.rollCall.departure.state,
        cell: ({ row }) => <CallStatePill driver={row.original} />,
      },
      {
        id: "alcohol",
        header: "アルコール",
        accessorFn: (d) => d.rollCall.departure.alcohol ?? -1,
        cell: ({ row }) => <AlcoholReading value={row.original.rollCall.departure.alcohol} />,
      },
      {
        id: "currency",
        header: "資格",
        accessorFn: (d) => worstCurrency(d),
        cell: ({ row }) => {
          const st = worstCurrency(row.original)
          return (
            <Badge variant={st === "有効" ? "success" : st === "期限間近" ? "warning" : "destructive"}>
              {st}
            </Badge>
          )
        },
      },
      {
        id: "kousoku",
        header: "拘束時間",
        accessorFn: (d) => d.kousokuMin,
        cell: ({ row }) => {
          const d = row.original
          if (d.shift !== "出番") return <span className="text-xs text-muted-foreground">—</span>
          return (
            <div className="w-28">
              <Meter
                value={d.kousokuMin}
                max={KAIZEN.dailyKousokuLimitMin}
                size="inline"
                label={`${d.name}の拘束時間`}
                formatValue={(v) => `${Math.floor(v / 60)}h${String(Math.round(v % 60)).padStart(2, "0")}`}
              />
            </div>
          )
        },
      },
    ],
    []
  )

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="flex items-center gap-2 text-base">
          <IconClipboardCheck className="size-5 text-primary" aria-hidden />
          乗務員名簿・点呼状況
        </CardTitle>
      </CardHeader>
      <CardContent>
        <DataTable
          columns={columns}
          data={drivers}
          filter={{ columnId: "driver", placeholder: "氏名で絞り込み…" }}
          pageSize={10}
          onRowClick={(d) => onSelect(d.id)}
          getRowState={(d) => (d.id === selectedId ? "selected" : undefined)}
        />
      </CardContent>
    </Card>
  )
}

// ── 乗務員詳細（資格・日報・拘束・点呼記録）────────────────────────────────
function DriverDetail({
  driver,
  signoff,
  onSign,
}: {
  driver: Driver
  signoff: CoSignValue | undefined
  onSign: (v: CoSignValue) => void
}) {
  const dep = driver.rollCall.departure
  const arr = driver.rollCall.arrival
  const alcoholDetected = dep.alcohol != null && dep.alcohol > 0

  return (
    <Card>
      <CardHeader className="pb-3">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <PersonCell
            name={driver.name}
            secondary={`${driver.kana}・社員№${driver.empNo}`}
            tertiary={`${driver.team}／${driver.employment}`}
            size="lg"
            avatarClassName="bg-primary/15 text-foreground"
          />
          <div className="flex items-center gap-2">
            <Badge variant="outline">無事故 {driver.noAccidentDays.toLocaleString()}日</Badge>
            <CallStatePill driver={driver} />
          </div>
        </div>
      </CardHeader>
      <CardContent>
        {alcoholDetected ? (
          <Alert variant="destructive" className="mb-4">
            <IconTestPipe />
            <AlertTitle>アルコール検知 — 出庫不可</AlertTitle>
            <AlertDescription>
              出庫点呼で {dep.alcohol!.toFixed(2)}mg/L を検知しました。基準値 0.00mg/L
              を超過しているため乗務できません。再測定・原因聴取の上、乗務を差し替えてください。
            </AlertDescription>
          </Alert>
        ) : null}

        <Tabs defaultValue="rollcall">
          <TabsList>
            <TabsTrigger value="rollcall">点呼</TabsTrigger>
            <TabsTrigger value="currency">資格・期限</TabsTrigger>
            <TabsTrigger value="report">本日の日報</TabsTrigger>
            <TabsTrigger value="legality">拘束時間</TabsTrigger>
          </TabsList>

          {/* ── 点呼 ── */}
          <TabsContent value="rollcall" className="space-y-4 p-4">
            <RollCallBlock title="出庫点呼" icon={<IconUserCheck className="size-4" />}>
              <MetadataList
                items={[
                  { label: "状態", value: <CallStatePill driver={driver} /> },
                  {
                    label: "点呼方法",
                    value: dep.method ?? "—",
                  },
                  {
                    label: "アルコール",
                    value: <AlcoholReading value={dep.alcohol} />,
                    icon: <IconTestPipe className="size-4" />,
                  },
                  {
                    label: "健康確認",
                    value: dep.health ? (
                      <Badge
                        variant={
                          dep.health === "良" ? "success" : dep.health === "要観察" ? "warning" : "destructive"
                        }
                        icon={<IconStethoscope />}
                      >
                        {dep.health}
                      </Badge>
                    ) : (
                      "—"
                    ),
                  },
                  { label: "点呼執行者", value: dep.executor ?? "—" },
                  { label: "実施時刻", value: dep.at ?? "—" },
                ]}
              />
              {dep.instruction ? (
                <Alert variant="info" className="mt-3">
                  <IconClipboardCheck />
                  <AlertTitle>指示伝達事項</AlertTitle>
                  <AlertDescription>{dep.instruction}</AlertDescription>
                </Alert>
              ) : null}
            </RollCallBlock>

            <Separator />

            <RollCallBlock title="帰庫点呼" icon={<IconClock className="size-4" />}>
              <MetadataList
                items={[
                  {
                    label: "状態",
                    value:
                      arr.state === "未了" ? (
                        <Badge variant="warning">未了</Badge>
                      ) : arr.state === "完了" ? (
                        <Badge variant="success">完了</Badge>
                      ) : (
                        <Badge variant="secondary">対象外</Badge>
                      ),
                  },
                  { label: "点呼方法", value: arr.method ?? "—" },
                  { label: "アルコール", value: <AlcoholReading value={arr.alcohol} /> },
                ]}
              />
            </RollCallBlock>

            <Separator />

            {/* ── 点呼記録の確認（2人確認でロック）── */}
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                <IconLock className="size-4 text-muted-foreground" aria-hidden />
                <h4 className="text-sm font-semibold">点呼記録の確認・確定</h4>
              </div>
              <p className="text-xs text-muted-foreground">
                点呼執行者（{dep.executor ?? "相原 健一"}）の記録を補助者が2人確認し、確定します。確定後は追記のみ。
              </p>
              <CoSign
                primaryId={dep.executor ?? "相原 健一"}
                value={signoff}
                onSign={onSign}
                requireReason={alcoholDetected}
                attestations={[
                  { id: "alcohol", label: "アルコール測定値・健康状態を確認した" },
                  { id: "currency", label: "資格・有効期限に乗務不可事由が無いことを確認した" },
                  { id: "instruction", label: "指示伝達事項を伝達した" },
                ]}
                signerLabel="確認者ID（補助者）"
              />
            </div>
          </TabsContent>

          {/* ── 資格・期限 ── */}
          <TabsContent value="currency" className="space-y-2 p-4">
            <div className="mb-2 flex items-center gap-2 text-sm font-semibold">
              <IconCalendarStats className="size-4 text-muted-foreground" aria-hidden />
              資格・診断の有効期限
            </div>
            <div className="divide-y divide-border">
              {driver.currencies.map((c) => (
                <CurrencyRow key={c.kind} kind={c.kind} expiry={c.expiry} note={c.note} />
              ))}
            </div>
            <p className="pt-2 text-xs text-muted-foreground">
              期限間近＝60日以内。失効を検知した場合は即時乗務停止・差し替え。
            </p>
          </TabsContent>

          {/* ── 日報・営収 ── */}
          <TabsContent value="report" className="p-4">
            {driver.report ? (
              <DailyReportBlock driver={driver} />
            ) : (
              <p className="rounded-md border border-dashed px-4 py-8 text-center text-sm text-muted-foreground">
                本日の乗務記録はありません（{driver.shift === "出番" ? "出庫保留／未乗務" : driver.shift}）。
              </p>
            )}
          </TabsContent>

          {/* ── 拘束時間 ── */}
          <TabsContent value="legality" className="space-y-5 p-4">
            <LegalityBlock driver={driver} />
          </TabsContent>
        </Tabs>
      </CardContent>
    </Card>
  )
}

function RollCallBlock({
  title,
  icon,
  children,
}: {
  title: string
  icon: React.ReactNode
  children: React.ReactNode
}) {
  return (
    <section className="space-y-2">
      <h4 className="flex items-center gap-2 text-sm font-semibold text-foreground">
        <span className="text-muted-foreground" aria-hidden>
          {icon}
        </span>
        {title}
      </h4>
      {children}
    </section>
  )
}

// ── 日報・営収内訳 ─────────────────────────────────────────────────────────
function DailyReportBlock({ driver }: { driver: Driver }) {
  const r = driver.report!
  const total = suiage(r)
  const rate = jissyaRate(r)
  return (
    <div className="space-y-5">
      <div>
        <div className="mb-2 flex items-center gap-2 text-sm font-semibold">
          <IconReceiptYen className="size-4 text-muted-foreground" aria-hidden />
          営収内訳（水揚）
        </div>
        <AmountBreakdown
          lines={[
            { label: "運賃（メーター）", amount: r.fare },
            { label: "迎車料金", amount: r.pickup },
            { label: "割増（深夜・早朝）", amount: r.premium },
            {
              type: "subtotal",
              label: "水揚",
              amount: total,
            },
            { type: "heading", label: "立替・参考" },
            {
              label: "高速・有料道路 立替",
              amount: r.tollAdvance,
              note: "乗客預り（売上外）",
            },
          ]}
          total={{ label: "水揚 合計", amount: total, tone: "positive" }}
          formula="水揚 ＝ 運賃 ＋ 迎車料 ＋ 割増"
        />
      </div>

      <Separator />

      <div>
        <div className="mb-2 text-sm font-semibold">走行・実車指標</div>
        <MetadataList
          layout="horizontal"
          items={[
            { label: "実車キロ", value: `${r.loadedKm.toFixed(1)} km` },
            { label: "走行キロ", value: `${r.totalKm.toFixed(1)} km` },
            { label: "実車率", value: `${rate}%` },
            { label: "乗車回数", value: `${r.trips} 回` },
            { label: "現金", value: formatCurrency(r.cash) },
            { label: "キャッシュレス", value: formatCurrency(r.cashless) },
          ]}
        />
      </div>

      <div>
        <div className="mb-2 text-sm font-semibold">実車率</div>
        <Meter
          value={r.loadedKm}
          max={r.totalKm}
          direction="higher-is-better"
          target={r.totalKm * 0.55}
          label={`${driver.name}の実車率`}
          unit=" km"
          formatValue={(v) => `${v.toFixed(1)}km`}
        />
        <p className="mt-1 text-xs text-muted-foreground">目標実車率 55%（実車キロ／走行キロ）。</p>
      </div>
    </div>
  )
}

// ── 拘束時間・連続乗務（改善基準告示）─────────────────────────────────────
function LegalityBlock({ driver }: { driver: Driver }) {
  if (driver.shift !== "出番") {
    return (
      <p className="rounded-md border border-dashed px-4 py-8 text-center text-sm text-muted-foreground">
        出番ではないため拘束時間の積算はありません（{driver.shift}）。
      </p>
    )
  }
  const k = driver.kousokuMin
  const r = driver.renzokuMin
  return (
    <>
      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <span className="flex items-center gap-2 text-sm font-semibold">
            <IconClock className="size-4 text-muted-foreground" aria-hidden />
            拘束時間（当日積算）
          </span>
          <span className="text-xs text-muted-foreground">
            上限 {KAIZEN.dailyKousokuLimitMin / 60}時間（改善基準告示・隔日勤務）
          </span>
        </div>
        <Meter
          value={k}
          max={KAIZEN.dailyKousokuLimitMin}
          label={`${driver.name}の拘束時間`}
          formatValue={(v) => `${Math.floor(v / 60)}時間${String(Math.round(v % 60)).padStart(2, "0")}分`}
        />
      </div>

      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <span className="flex items-center gap-2 text-sm font-semibold">
            <IconGauge className="size-4 text-muted-foreground" aria-hidden />
            連続乗務（実車）
          </span>
          <span className="text-xs text-muted-foreground">
            目安 {KAIZEN.renzokuLimitMin / 60}時間で要休憩
          </span>
        </div>
        <Meter
          value={r}
          max={KAIZEN.renzokuLimitMin}
          thresholds={{ warning: 0.85, over: 1 }}
          label={`${driver.name}の連続乗務`}
          formatValue={(v) => `${Math.floor(v / 60)}時間${String(Math.round(v % 60)).padStart(2, "0")}分`}
        />
        {r >= KAIZEN.renzokuLimitMin - 10 ? (
          <p className="text-xs text-warning">連続乗務が上限に接近しています。休憩を指示してください。</p>
        ) : null}
      </div>

      <Separator />

      <CheckList
        items={[
          {
            id: "rest",
            label: "休憩の確保",
            description: "連続乗務4時間ごとに30分以上",
            trailing: <Badge variant={r < KAIZEN.renzokuLimitMin ? "success" : "warning"}>確認</Badge>,
          },
          {
            id: "kousoku",
            label: "拘束時間の上限",
            description: `当日 ${Math.floor(k / 60)}時間${k % 60}分／上限 ${KAIZEN.dailyKousokuLimitMin / 60}時間`,
            trailing: (
              <Badge variant={k < KAIZEN.dailyKousokuLimitMin * 0.9 ? "success" : "warning"}>
                {k < KAIZEN.dailyKousokuLimitMin * 0.9 ? "余裕" : "接近"}
              </Badge>
            ),
          },
        ]}
      />
    </>
  )
}
